const e={topicId:"noun-gender",title:"Romanian Noun Gender: Masculine, Feminine & Neuter",introduction:"Romanian is one of the few Romance languages that preserves three grammatical genders from Latin: masculine, feminine, and neuter. Understanding gender is essential because it affects articles, adjective agreement, and pronoun usage. The good news is that noun endings often reveal the gender.",sections:[{id:"gender-overview",title:"The Three Genders",blocks:[{type:"rule",title:"Three Genders in Romanian",content:"Every Romanian noun belongs to one of three genders: masculine (masculin), feminine (feminin), or neuter (neutru). The neuter gender is unique among Romance languages — neuter nouns behave like masculine in the singular and feminine in the plural."},{type:"table",headers:["Gender","Singular Article","Plural Article","Examples"],rows:[["Masculine","un (indefinite)","niște","un băiat, un câine, un copac"],["Feminine","o (indefinite)","niște","o fată, o casă, o floare"],["Neuter","un (indefinite)","niște","un scaun, un tren, un oraș"]],caption:"The three Romanian genders with indefinite articles",colorCoded:!0},{type:"callout",variant:"info",content:"Romanian is the only Romance language that kept the neuter gender from Latin. Neuter nouns use masculine forms in the singular and feminine forms in the plural."}]},{id:"masculine-nouns",title:"Masculine Nouns",blocks:[{type:"text",content:"Masculine nouns typically end in a consonant in their base (dictionary) form. Male persons and animals are almost always masculine."},{type:"table",headers:["Ending","Examples"],rows:[["consonant","băiat (boy), om (man), câine (dog), frate (brother)"],["-e (some)","perete (wall), soare (sun), munte (mountain)"]],caption:"Common masculine noun endings"},{type:"example",romanian:"Un băiat merge la școală.",english:"A boy goes to school.",highlights:[{text:"Un",role:"article"},{text:"băiat",role:"subject"},{text:"merge",role:"verb"}]},{type:"example",romanian:"Fratele meu este profesor.",english:"My brother is a teacher.",highlights:[{text:"Fratele",role:"subject"},{text:"este",role:"verb"}]}]},{id:"feminine-nouns",title:"Feminine Nouns",blocks:[{type:"text",content:"Feminine nouns most commonly end in -ă or -e. Female persons and animals are almost always feminine."},{type:"table",headers:["Ending","Examples"],rows:[["-ă","casă (house), masă (table), carte (book), fată (girl)"],["-e","floare (flower), pâine (bread), noapte (night)"],["-are, -ere, -ire","mâncare (food), plăcere (pleasure), iubire (love)"]],caption:"Common feminine noun endings"},{type:"example",romanian:"O fată citește o carte.",english:"A girl reads a book.",highlights:[{text:"O",role:"article"},{text:"fată",role:"subject"},{text:"citește",role:"verb"},{text:"o carte",role:"object"}]}]},{id:"neuter-nouns",title:"Neuter Nouns",blocks:[{type:"rule",title:"The Neuter Acts Like Two Genders",content:'Neuter nouns take masculine forms in the singular (un scaun) and feminine forms in the plural (niște scaune). This is why some grammarians call it "ambigeneric" rather than truly neuter.'},{type:"comparison",left:{title:"Singular (like masculine)",items:["un scaun (a chair)","un tren (a train)","un oraș (a city)","un tablou (a painting)"]},right:{title:"Plural (like feminine)",items:["niște scaune (some chairs)","niște trenuri (some trains)","niște orașe (some cities)","niște tablouri (some paintings)"]}},{type:"example",romanian:"Un tren pleacă din gară.",english:"A train leaves from the station.",highlights:[{text:"Un",role:"article"},{text:"tren",role:"subject"},{text:"pleacă",role:"verb"}]},{type:"callout",variant:"tip",content:"Many objects and abstract concepts are neuter: un scaun (chair), un caiet (notebook), un cuvânt (word), un loc (place). If a noun ends in a consonant and its plural ends in -uri or -e, it is likely neuter."}]},{id:"identifying-gender",title:"How to Identify Gender from Endings",blocks:[{type:"decision",question:"Does the noun end in -ă?",yes:{answer:"Almost certainly feminine.",explanation:"Nouns ending in -ă are feminine in the vast majority of cases: casă, masă, fată, țară."},no:{answer:"Check further.",followUp:{question:"Does the noun end in a consonant?",yes:{answer:"Likely masculine or neuter.",explanation:"Check the plural: if the plural ends in -i, it is masculine (băiat → băieți). If the plural ends in -uri or -e, it is neuter (tren → trenuri)."},no:{answer:"Could be any gender.",explanation:"Nouns ending in -e can be masculine (soare), feminine (floare), or neuter (nume). You need to learn these individually."}}}},{type:"callout",variant:"warning",content:'Some nouns ending in -e are tricky: "soare" (sun) is neuter, "floare" (flower) is feminine, and "perete" (wall) is masculine. When in doubt, check the plural form to determine the gender.'}]}]};export{e as default};
